<?php $error=''; if($_SERVER['REQUEST_METHOD']==='POST'){verify_csrf($_POST['csrf']??null);foreach(['project_name','location','description','status','price','google_map'] as $f)$project[$f]=trim($_POST[$f]??'');try{if(mb_strlen($project['project_name'])<2||mb_strlen($project['description'])<10)throw new RuntimeException('Project name and description are required.');$thumbnail=$project['thumbnail']??'';if(($_FILES['thumbnail']['error']??UPLOAD_ERR_NO_FILE)!==UPLOAD_ERR_NO_FILE)$thumbnail=upload_image($_FILES['thumbnail'],'projects');if(!$thumbnail)throw new RuntimeException('A project thumbnail is required.');if($editing){db()->prepare('UPDATE projects SET project_name=?,location=?,description=?,status=?,price=?,google_map=?,thumbnail=? WHERE id=?')->execute([$project['project_name'],$project['location'],$project['description'],$project['status'],$project['price'],$project['google_map'],$thumbnail,$project['id']]);}else{db()->prepare('INSERT INTO projects (project_name,location,description,status,price,google_map,thumbnail) VALUES (?,?,?,?,?,?,?)')->execute([$project['project_name'],$project['location'],$project['description'],$project['status'],$project['price'],$project['google_map'],$thumbnail]);}redirect('admin/projects.php');}catch(Throwable $e){$error=$e->getMessage();}} admin_head($editing?'Edit project':'Add project'); ?><h1><?= $editing?'Edit project':'Add project' ?></h1><form class="card" method="post" enctype="multipart/form-data"><?php if($error):?><p class="error"><?=e($error)?></p><?php endif?><input type="hidden" name="csrf" value="<?=csrf_token()?>"><label>Project name</label><input name="project_name" value="<?=e($project['project_name'])?>" required><label>Location</label><input name="location" value="<?=e($project['location'])?>" required><label>Description</label><textarea name="description" rows="6" required><?=e($project['description'])?></textarea><label>Status</label><select name="status"><?php foreach(['Upcoming','Ongoing','Completed'] as $status):?><option <?=$project['status']===$status?'selected':''?>><?=$status?></option><?php endforeach?></select><label>Price (optional)</label><input name="price" value="<?=e($project['price'])?>"><label>Google Map embed URL (optional)</label><input name="google_map" value="<?=e($project['google_map'])?>"><label>Thumbnail <?= $editing?'(leave blank to keep current image)':'' ?></label><input type="file" name="thumbnail" accept="image/jpeg,image/png,image/webp,image/gif" <?= $editing?'':'required' ?>><button><?= $editing?'Save changes':'Create project' ?></button></form><?php admin_foot(); ?>
